class Solution {
    public int numberOfSubstrings(String s) {
        int count = 0;
        int n = s.length();
        int[][] dp = new int[n + 1][3];

        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= 2; j++) {
                if (s.charAt(i - 1) == 'a') {
                    dp[i][j] = dp[i - 1][j] + dp[i - 1][j + 1];
                } else if (s.charAt(i - 1) == 'b') {
                    dp[i][j] = dp[i - 1][j];
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
            }
            count += dp[i][2];
        }
        return count;
    }
}
